skinparam classFontSize 14
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #333333
skinparam classArrowColor #333333
skinparam classStereotypeStyle none
skinparam classIconSize 20

class "sea" as sea {
}
class "pool" as pool {
}
class "bathtub" as bathtub {
}
class "universe" as universe {
}
class "solar_system" as solar_system {
}

sea --|> pool
pool *-- bathtub
universe o-- solar_system

note right of sea
  <b>C</b>
end note
note right of pool
  <b>C</b>
end note
note right of bathtub
  <b>C</b>
end note
note right of universe
  <b>C</b>
end note
note right of solar_system
  <b>C</b>
end note

@enduml
